def classify_ibex_sex(horn_length_cm, body_size_class):
    if horn_length_cm > 80 and body_size_class == 'large':
        return 'male'
    elif horn_length_cm < 50 and body_size_class == 'small':
        return 'female'
    else:
        return 'unknown'

# Example usage:
print(classify_ibex_sex(90, 'large'))  # Output: 'male'
print(classify_ibex_sex(40, 'small'))  # Output: 'female'
